import './Select.scss';

import { BottomSheet } from ':components/BottomSheet';
import { Icon } from ':components/Icon';
import type { NewDropdownMenuProps } from ':components/NewDropdownMenu';
import { NewDropdownMenu } from ':components/NewDropdownMenu';
import { PopoverContext } from ':components/Popover';
import { useOverflowText } from ':components/Select/components/hooks/useOverflowText';
import { Tooltip } from ':components/Tooltip';
import { classNames } from ':helpers/classnames';
import { getBEMClasses } from ':helpers/get-bem';
import { useDeviceSize } from ':helpers/use-device-size';
import { Icons } from '@beeline/design-tokens/js/iconfont';
import type { FocusEvent, KeyboardEvent as ReactKeyboardEvent } from 'react';
import React, { useMemo, useRef } from 'react';

import { TextField } from '../TextField';
import { DropDownContent } from './components/DropDownContent';
import { OverflowCount } from './components/OverflowCount';
import { defaultMakeOption } from './helpers';
import type { SelectProps } from './Select.types';
import { useSelect } from './useSelect';

const [selectClassName, , selectElement] = getBEMClasses('dsb__select');
const [optionsClassName, , optionsElement] = selectElement('options');
const [itemClassName] = optionsElement('item');

export const Select = <T,>({
	label,
	helperText,
	multiple,
	filter,
	filterPlaceholder = 'Поиск',
	filterFunction,
	size,
	error,
	values,
	renderValue,
	onChange,
	onClose,
	onOpen,
	onOutsideClick,
	onManualClickOption,
	open,
	onFocus,
	onBlur,
	options,
	fullWidth,
	className,
	disabled,
	makeOption,
	loading,
	loadingText,
	loadingContent,
	applicationRootElementID,
	dropdownElementID,
	dropdownClassName,
	dataTestId = 'Select',
	selectAll = false,
	selectAllText = 'Выбрать все',
	showTooltip = false,
	noOptionsText = 'Нет результатов',
	enableKeyboardNavigation = false,
	isShowCountOfValues = false,
	overlayScroll = true,
	shouldRenderOverlay,
	overlayClassName,
	alignDropDown,
	makeOptionWrapper,
	compareBy,
	hideDropDown = false,
	disableMobileBottomSheet = false,
	groups,
	onClick,
	onKeyDown: externalOnKeyDown,
	...props
}: SelectProps<T>): React.JSX.Element => {
	const inputRef = useRef<HTMLInputElement>(null);
	const filterRef = useRef<HTMLInputElement>(null);
	const selectRef = useRef<HTMLDivElement>(null);
	const switchButtonRef = useRef<HTMLButtonElement>(null);
	const optionsRef = useRef<HTMLDivElement>(null);

	const { isExtraSmallDevice } = useDeviceSize();
	const useMobileBottomSheet = isExtraSmallDevice && !disableMobileBottomSheet;

	const selectAllIndex = -2;

	const {
		isOpen,
		setOpen,
		filterValue,
		disableTooltip,
		privateOptions,
		privateValues,
		inputLabel,
		handleOpen,
		handleClose,
		onSelectItem,
		onMultiselectItem,
		focusedIndex,
		focusedOptionId,
		handleSelectAll,
		getSelectAllStatus,
		changeFilterValue,
	} = useSelect({
		open,
		onOpen,
		onClose,
		onChange,
		options,
		values,
		renderValue,
		filter,
		filterFunction,
		enableKeyboardNavigation,
		multiple,
		selectAll,
		inputRef,
		filterRef,
		dropdownRef: selectRef,
		showTooltip,
		onFocus,
		onBlur,
		selectAllText,
		noOptionsText,
		disabled,
		onManualClickOption,
		makeOption,
		loading,
		loadingText,
		loadingContent,
		optionsRef,
		compareBy,
		groups,
	});

	const handleInputBlur = (event: FocusEvent<HTMLInputElement>): void => {
		if (!isOpen) {
			onBlur?.(event);
			inputRef.current?.blur();
		}
	};

	const handleInputFocus = (event: FocusEvent<HTMLInputElement>): void => {
		onFocus?.(event);
		inputRef.current?.focus();
	};

	const handleInputClick = (e): void => {
		onClick?.(e);
		isOpen ? handleClose() : handleOpen();
	};

	const handleInputKeyDown = (event: ReactKeyboardEvent<HTMLInputElement>): void => {
		externalOnKeyDown?.(event);
		if (!enableKeyboardNavigation || disabled || isOpen || event.defaultPrevented) {
			return;
		}

		if (event.key === 'Enter' || event.key === ' ' || event.key === 'ArrowDown') {
			event.preventDefault();
			handleOpen();
		}
	};

	const handleSetOpenWrapper = (newOpen: boolean): void => {
		if (newOpen) {
			handleOpen();
		} else {
			handleClose();
		}
	};

	React.useEffect(() => {
		if (!isOpen) {
			return;
		}

		const handleEsc = (event: KeyboardEvent): void => {
			if (event.key === 'Escape') {
				onOutsideClick?.();
			}
		};

		document.addEventListener('keydown', handleEsc);
		return () => document.removeEventListener('keydown', handleEsc);
	}, [isOpen, onOutsideClick]);

	const dropdownMenuProps: NewDropdownMenuProps = {
		targetElement: inputRef,
		verticalOffset: 1,
		applicationRootElementID,
		dropdownElementID,
		className: dropdownClassName,
		onBlur,
		isOpen,
		handleSetOpen: handleSetOpenWrapper,
		onOutsideClick,
		overlayScroll,
		shouldRenderOverlay,
		overlayClassName,
		align: alignDropDown,
	};

	const isIconName = isOpen ? Icons.NavArrowUp : Icons.NavArrowDown;
	const rightIcon = <Icon ref={switchButtonRef} size={size} iconName={isIconName} />;

	const rootClassName = classNames(selectClassName, Boolean(className) && className);
	const popoverContextValue = useMemo(
		() => ({
			applicationRootElementId: 'root',
			popoverRootElementID: 'select-popover',
		}),
		[],
	);

	const hiddenRef = useRef<HTMLParagraphElement>(null);
	const countRef = useRef<HTMLParagraphElement>(null);
	const { count, className: overflowClassName } = useOverflowText({
		hiddenRef,
		inputRef,
	});

	const counter = (
		<p className={overflowClassName} ref={countRef}>
			(+{count})
		</p>
	);

	const optionsClassNameWithBottomSheet = classNames(optionsClassName, {
		dsb__select__options_in_bottom_sheet: useMobileBottomSheet,
	});

	const dropDownContentProps = {
		selectedItems: privateValues,
		optionsData: privateOptions,
		selectAll,
		filter,
		filterValue,
		filterFunction,
		selectAllIndex,
		optionsClassName: optionsClassNameWithBottomSheet,
		multiple,
		itemClassName,
		onMultiselectItem,
		onManualClickOption,
		onSelectItem,
		focusedIndex,
		handleSelectAll,
		makeOption,
		showTooltip,
		defaultMakeOption,
		selectAllText,
		loading,
		loadingText,
		loadingContent,
		noOptionsText,
		optionsRef,
		selectStatus: getSelectAllStatus(),
		filterPlaceholder,
		filterRef,
		changeFilterValue,
		dataTestId,
		selectRef,
		makeOptionWrapper,
		groups,
		unstyled: useMobileBottomSheet,
	};

	return (
		<div className={rootClassName} data-testid={dataTestId}>
			{isShowCountOfValues && (
				<OverflowCount inputRef={inputRef} hiddenRef={hiddenRef} values={values} countRef={countRef} />
			)}
			<PopoverContext.Provider value={popoverContextValue}>
				<Tooltip title={inputLabel} disableHover={disableTooltip}>
					<TextField
						ref={inputRef}
						label={label}
						helperText={helperText}
						size={size}
						error={error}
						aria-invalid={error}
						role="combobox" // NOSONAR S6819 - WAI-ARIA combobox pattern, native select doesn't support filter/groups/custom options
						aria-expanded={isOpen}
						aria-haspopup="listbox"
						aria-controls={`${dataTestId}-listbox`}
						aria-activedescendant={
							focusedOptionId !== undefined ? `${dataTestId}-option-${focusedOptionId}` : undefined
						}
						fullWidth={fullWidth}
						endAdornment={rightIcon}
						onBlur={handleInputBlur}
						onFocus={handleInputFocus}
						onClick={handleInputClick}
						onKeyDown={handleInputKeyDown}
						disabled={disabled}
						value={inputLabel}
						contentEditable={true}
						isClickableAdornment={false}
						readOnly
						dataTestId={dataTestId + '-textfield'}
						isShowCountOfValues={isShowCountOfValues}
						counter={counter}
						isFocused={isOpen}
						{...props}
					/>
				</Tooltip>
			</PopoverContext.Provider>
			{isOpen && !hideDropDown && !useMobileBottomSheet && (
				<NewDropdownMenu {...dropdownMenuProps}>
					{/* TODO посмотреть на расчет ширины и переделать */}
					{/* TODO Нормализоват пропсы для этого компонента, сейчас слишком много зависимостей */}
					<DropDownContent {...dropDownContentProps} />
				</NewDropdownMenu>
			)}
			{isOpen && !hideDropDown && useMobileBottomSheet && (
				<BottomSheet
					isOpen={isOpen}
					handleSetOpen={setOpen}
					modal={true}
					onOutsideClick={onOutsideClick}
					header={{
						title: label || 'Выберите значение',
						closeButton: true,
					}}
					className={dropdownClassName}
				>
					<DropDownContent {...dropDownContentProps} />
				</BottomSheet>
			)}
		</div>
	);
};

Select.propTypes = {
	open: (props: Record<string, unknown>, propName: string, componentName: string): Error => {
		if (Object.prototype.hasOwnProperty.call(props, propName) && (!props.onClose || !props.onOpen)) {
			return new Error(
				`It seems you forgot pass 'onClose' and 'onOpen' props, please check.
					'open' prop should be using both with 'onClose' and 'onOpen' props in '${componentName}'.`,
			);
		}
	},
};
